urlset:
{% for url in static_urls %}

    {{ url }}
    {{ now.strftime('%Y-%m-%d') }}
    weekly
    0.8

{% endfor %}

{% for project in projects %}
{% if project.slug %}

    {{ url_for('portfolio.project_detail', slug=project.slug, _external=True, _scheme='https') }}
    {{ project.deployed_at.strftime('%Y-%m-%d') if project.deployed_at else now.strftime('%Y-%m-%d') }}
    monthly
    0.9

{% endif %}
{% endfor %}

{% for post in blog_posts %}
{% if post.slug %}

    {{ url_for('blog.blog_detail', slug=post.slug, _external=True, _scheme='https') }}
    {{ post.updated_at.strftime('%Y-%m-%d') if post.updated_at else now.strftime('%Y-%m-%d') }}
    weekly
    0.7

{% endif %}
{% endfor %}

{% for service in services %}
{% if service.slug %}

    {{ url_for('services.service_detail', slug=service.slug, _external=True, _scheme='https') }}
    {{ service.updated_at.strftime('%Y-%m-%d') if service.updated_at else now.strftime('%Y-%m-%d') }}
    monthly
    0.8

{% endif %}
{% endfor %}

{% for faq in faqs %}
{% if faq.slug %}

    {{ url_for('faq.faq_detail', slug=faq.slug, _external=True, _scheme='https') }}
    {{ faq.updated_at.strftime('%Y-%m-%d') if faq.updated_at else now.strftime('%Y-%m-%d') }}
    monthly
    0.6

{% endif %}
{% endfor %}
